#include <bits/stdc++.h>
using namespace std;
int f[10004],n,m;
int find(int x){
	if(f[x]==x)return x;
	return f[x]=find(f[x]);
}
void merge(int x,int y){
	int f_x=find(x),f_y=find(y);
	if(f_x!=f_y)f[f_y]=f_x;
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)f[i]=i;
    for(int i=1;i<=m;i++){
        int z,x,y;
        cin>>z>>x>>y;
        if(z==1)
            merge(x,y);
        else
            if(find(x)==find(y))
                cout<<"Y\n";
            else
                cout<<"N\n";
    }
    return 0;
}
